import {readFile, writeFile} from 'node:fs/promises';
import path from 'node:path';
import {fileURLToPath} from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoOwner = 'openagentmarket';
const repoName = 'openagent';
const apiUrl = `https://api.github.com/repos/${repoOwner}/${repoName}`;
const outputPath = path.join(
  __dirname,
  '..',
  'apps',
  'landing',
  'src',
  'lib',
  'github-stars.ts',
);

function renderModule(stars, updatedAt) {
  return `// Generated by scripts/fetch-landing-stars.mjs
// Do not edit manually.

export const OPENAGENT_STARS = ${stars === null ? 'null' : stars};
export const OPENAGENT_STARS_UPDATED_AT = ${JSON.stringify(updatedAt)};
`;
}

async function readExistingStars() {
  try {
    const existing = await readFile(outputPath, 'utf8');
    const match = existing.match(/OPENAGENT_STARS = (null|\d+)/);
    if (!match) {
      return null;
    }
    return match[1] === 'null' ? null : Number(match[1]);
  } catch {
    return null;
  }
}

async function fetchStars() {
  const headers = {
    Accept: 'application/vnd.github+json',
    'X-GitHub-Api-Version': '2022-11-28',
  };

  if (process.env.GITHUB_TOKEN) {
    headers.Authorization = `Bearer ${process.env.GITHUB_TOKEN}`;
  }

  const response = await fetch(apiUrl, {headers});

  if (!response.ok) {
    throw new Error(`GitHub API returned ${response.status}`);
  }

  const data = await response.json();
  const stars = data?.stargazers_count;

  if (typeof stars !== 'number') {
    throw new Error('GitHub API response did not include a numeric stargazers_count');
  }

  return stars;
}

async function main() {
  const previousStars = await readExistingStars();
  let stars = previousStars;

  try {
    stars = await fetchStars();
    console.log(`Fetched OpenAgent stars: ${stars}`);
  } catch (error) {
    console.warn(
      `Falling back to cached OpenAgent stars because fetch failed: ${error instanceof Error ? error.message : String(error)}`,
    );
  }

  const updatedAt = new Date().toISOString();
  await writeFile(outputPath, renderModule(stars, updatedAt), 'utf8');
  console.log(`Wrote star snapshot to ${outputPath}`);
}

await main();
